import { Effect, Console } from "effect"

export const traceEffect = <A, E, R>(
  label: string,
  eff: Effect.Effect<A, E, R>
): Effect.Effect<A, E, R> =>
  Effect.tapBoth(eff, {
    onSuccess: (a) => Console.log(`[${label}] ok`, a),
    onFailure: (e) => Console.error(`[${label}] err`, e)
  })

const demo = Effect.succeed(42)
const traced = traceEffect("demo", demo)
void Effect.runPromise(traced)
