import { Effect } from "effect"

export const withDefault = <A, E, R>(
  eff: Effect.Effect<A, E, R>,
  fallback: A
): Effect.Effect<A, never, R> =>
  Effect.catchAll(eff, () => Effect.succeed(fallback))

const broken: Effect.Effect<number, string, never> = Effect.fail("boom")
const safe = withDefault(broken, 0)
void Effect.runPromise(safe).then((n) => n)
```

Keeping `<A, E, R>` polymorphic lets callers plug in any payload / error / env without forcing a least-upper-bound. The utility stays compositional because TypeScript propagates the caller-supplied types through `Effect.raceAll`, whose result tuple is `Effect<A, E, R>` with the same parameters. Widening them to `unknown` in the signature would force every call-site to `as` back, defeating the point.

```typescript
import { Effect } from "effect"

export const firstSuccess = <A, E, R>(
  head: Effect.Effect<A, E, R>,
  tail: ReadonlyArray<Effect.Effect<A, E, R>>
): Effect.Effect<A, E, R> =>
  Effect.raceAll([head, ...tail])

const a = Effect.succeed("a")
const b = Effect.succeed("b")
void Effect.runPromise(firstSuccess(a, [b]))
```

