import { Effect, pipe } from "effect"

export const mapBoth = <A, B, E, E2, R>(
  eff: Effect.Effect<A, E, R>,
  onError: (e: E) => E2,
  onSuccess: (a: A) => B
): Effect.Effect<B, E2, R> =>
  pipe(eff, Effect.mapError(onError), Effect.map(onSuccess))

const src: Effect.Effect<number, string, never> = Effect.fail("bad")
const out = mapBoth(src, (e) => new Error(e), (n) => n + 1)
void Effect.runPromise(Effect.either(out))
