import { Effect } from "effect"

export const timed = <A, E, R>(
  eff: Effect.Effect<A, E, R>
): Effect.Effect<readonly [number, A], E, R> =>
  Effect.gen(function* () {
    const start = Date.now()
    const a = yield* eff
    return [Date.now() - start, a] as const
  })

const prog = Effect.succeed("done")
void Effect.runPromise(timed(prog))
