import { Data, Match } from "effect"

type Shape = Data.TaggedEnum<{
  Circle: { radius: number }
  Square: { side: number }
  Rectangle: { width: number; height: number }
}>

const Shape = Data.taggedEnum<Shape>()

export const area = (s: Shape): number =>
  Match.value(s).pipe(
    Match.tag("Circle", ({ radius }) => Math.PI * radius * radius),
    Match.tag("Square", ({ side }) => side * side),
    Match.tag("Rectangle", ({ width, height }) => width * height),
    Match.exhaustive
  )

const s: Shape = Shape.Circle({ radius: 3 })
void area(s)
