```typescript
import { Data, Equal, Effect } from "effect"

interface Point { readonly x: number; readonly y: number }

export const Point = (x: number, y: number): Point =>
  Data.struct({ x, y })

const p1 = Point(1, 2)
const p2 = Point(1, 2)
export const eqProgram: Effect.Effect<boolean> = Effect.succeed(Equal.equals(p1, p2))
void Effect.runPromise(eqProgram)
```

`Data.case` produces a constructor that adds structural equality and hashing to your record at no runtime cost beyond a prototype stamp. Two calls with deep-equal arguments become `Equal.equals`-equal values — something you would otherwise have to hand-roll with an `equals` method or a third-party deep-equal. You still get full TypeScript inference from the type argument, so downstream pipelines keep the exact shape you declared.

```typescript
import { Data, Equal, Effect } from "effect"

interface User {
  readonly id: string
  readonly name: string
}
const User = Data.case<User>()

const u1 = User({ id: "u1", name: "Ada" })
const u2 = User({ id: "u1", name: "Ada" })
export const eqProg: Effect.Effect<boolean> = Effect.succeed(Equal.equals(u1, u2))
void Effect.runPromise(eqProg)
```

