    Match.tag("Click", ({ x, y }) => `click@${x},${y}`),
    Match.tag("Hover", ({ target }) => `hover:${target}`),
    Match.tag("Submit", ({ form }) => `submit:${form}`),
    Match.exhaustive
  )

void describe(Event.Click({ x: 1, y: 2 }))
