import { Effect, Context, Layer } from "effect"

interface Logger { readonly log: (s: string) => Effect.Effect<void> }
const Logger = Context.GenericTag<Logger>("app/Logger")

interface Clock { readonly now: () => Effect.Effect<number> }
const Clock = Context.GenericTag<Clock>("app/Clock")

const needsLogger: Effect.Effect<void, never, Logger> = Effect.gen(function* () {
  const l = yield* Logger
  yield* l.log("hi")
})

// Adding a Clock requirement widens R; original Logger requirement stays.
const needsBoth: Effect.Effect<void, never, Logger | Clock> = Effect.gen(function* () {
  yield* needsLogger
  const c = yield* Clock
  yield* c.now()
})

const liveLogger = Layer.succeed(Logger, { log: (s) => Effect.sync(() => void s) })
const liveClock = Layer.succeed(Clock, { now: () => Effect.succeed(0) })
void Effect.runPromise(Effect.provide(needsBoth, Layer.merge(liveLogger, liveClock)))
```

