import { Effect, Context, Layer } from "effect"

interface Logger { readonly log: (s: string) => Effect.Effect<void> }
const Logger = Context.GenericTag<Logger>("app/Logger")
interface DB { readonly ping: () => Effect.Effect<boolean> }
const DB = Context.GenericTag<DB>("app/DB")

const step1: Effect.Effect<void, never, Logger> = Effect.gen(function* () {
  const l = yield* Logger
  yield* l.log("s1")
})
const step2: Effect.Effect<boolean, never, Logger | DB> = Effect.gen(function* () {
  const db = yield* DB
  return yield* db.ping()
})

const combined: Effect.Effect<boolean, never, Logger | DB> = Effect.flatMap(step1, () => step2)

const layer = Layer.merge(
  Layer.succeed(Logger, { log: (s) => Effect.sync(() => void s) }),
  Layer.succeed(DB, { ping: () => Effect.succeed(true) })
)
void Effect.runPromise(Effect.provide(combined, layer))
```

