import * as E from "fp-ts/Either"

type NonEmptyString = string & { readonly _tag: "NonEmptyString" }

const isNonEmpty = (s: string): s is NonEmptyString => s.length > 0

export const fromPredicateRefined = <A, B extends A, Err>(
  pred: (a: A) => a is B,
  onFalse: (a: A) => Err
) => (a: A): E.Either<Err, B> => (pred(a) ? E.right(a) : E.left(onFalse(a)))

export const parseNE = fromPredicateRefined(isNonEmpty, () => "Empty" as const)
const r: E.Either<"Empty", NonEmptyString> = parseNE("hello")
void r
```

