import { Effect, Context, Layer } from "effect"

export type WithoutRequirements<T> =
  T extends Effect.Effect<infer A, infer E, infer _R> ? Effect.Effect<A, E, never> : never

interface Cfg { readonly n: number }
const Cfg = Context.GenericTag<Cfg>("app/Cfg")

const prog = Effect.gen(function* () { const c = yield* Cfg; return c.n })
const provided: WithoutRequirements<typeof prog> = Effect.provide(prog, Layer.succeed(Cfg, { n: 1 }))
void Effect.runPromise(provided)
